-- ---- remap dangling programme_id -> existing academic.programmes.id ----
SET @have_prog := (SELECT COUNT(*) FROM information_schema.tables
                   WHERE table_schema='mutupo_academic' AND table_name='programmes');
SET @prog_rows := 0;
SET @cntsql := IF(@have_prog>0,
  'SET @prog_rows := (SELECT COUNT(*) FROM mutupo_academic.programmes)', 'DO 0');
PREPARE _c FROM @cntsql; EXECUTE _c; DEALLOCATE PREPARE _c;
SET @remap := IF(@prog_rows>0,
'UPDATE students s
   JOIN (SELECT COUNT(*) c FROM mutupo_academic.programmes) cnt
   JOIN (SELECT id, ROW_NUMBER() OVER (ORDER BY id)-1 AS rn FROM mutupo_academic.programmes) r
     ON r.rn = (s.programme_id MOD cnt.c)
   LEFT JOIN mutupo_academic.programmes p ON p.id = s.programme_id
   SET s.programme_id = r.id
   WHERE s.programme_id IS NOT NULL AND p.id IS NULL', 'DO 0');
PREPARE _rm FROM @remap; EXECUTE _rm; DEALLOCATE PREPARE _rm;

SELECT COUNT(*) AS students_total FROM students;
